/**
 * Teams icon library.
 *
 * Every icon is an inline SVG React component sourced from the Fluent icon
 * dump in `public/assets/`. The path data is embedded directly so icons can
 * never fail to render — no network requests, no public-path lookups, no CSS
 * mask quirks. Fills are normalised to `currentColor` so the surrounding
 * `color` cascades through (matching how `@fluentui/react-icons` behaves).
 *
 * To add a new icon:
 *   1. Find the SVG in `slack-demos/public/assets/` (or in
 *      `Not in use/` for archived icons).
 *   2. Add a new component below with the path `d=...` and the icon's
 *      original `viewBox` (most are 0 0 24 24).
 *   3. Replace `fill="#242424"` (or any hardcoded fill) with
 *      `fill="currentColor"`.
 */
import type { SVGProps } from 'react'

export interface TeamsIconProps extends Omit<SVGProps<SVGSVGElement>, 'children'> {
  /** Pixel size (sets both width and height). Defaults to 20. */
  size?: number
}

interface IconShellProps extends TeamsIconProps {
  viewBox?: string
  path: string
}

function IconShell({ size = 20, viewBox = '0 0 24 24', path, ...rest }: IconShellProps) {
  return (
    <svg
      width={size}
      height={size}
      viewBox={viewBox}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden={rest['aria-label'] ? undefined : true}
      focusable="false"
      {...rest}
    >
      <path d={path} fill="currentColor" />
    </svg>
  )
}

